    Lidar lidar("192.168.1.2", 6201, "192.168.1.62", 6101);

    while (true)
    {
        auto packet_type = lidar.has_data();

        if (packet_type == 0)
        {
            std::this_thread::sleep_for(std::chrono::milliseconds(10));
            continue;
        }

        if (packet_type == POINT_DATA_PACKET_TYPE)
        {
            auto data = lidar.get_point_data();
            std::cout << "Point data received: " << data.com_horizontal_angle_start << std::endl;
        }
        else if (packet_type == IMU_DATA_PACKET_TYPE)
        {
            auto data = lidar.get_imu_data();
            std::cout << "IMU data received: " << data.linear_acceleration[2] << std::endl;
        }
        else
        {
            lidar.ignore_data();
        }
    }

    return 0;
